import{_ as e}from"./chunks/ue-plugin-enabled.Ln1oOl8v.js";import{_ as o}from"./chunks/settings-add-model.Cxj4wiLe.js";import{_ as a,o as i,c as n,ag as r}from"./chunks/framework.BqfgOMAh.js";const b=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/installation.md","filePath":"en/guide/installation.md"}'),l={name:"en/guide/installation.md"};function s(d,t,h,u,c,p){return i(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>This page provides a detailed walkthrough of the NexusFlow installation process. NexusFlow consists of two components that need to be installed separately:</p><ul><li><strong>Desktop App</strong> — Free, downloaded from GitHub</li><li><strong>UE Plugin</strong> — Purchased from Fab.com and installed into your UE engine</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Minimum Requirement</th></tr></thead><tbody><tr><td>Operating System</td><td>Windows 10 / 11 (64-bit)</td></tr><tr><td>Unreal Engine</td><td>Unreal Engine 5.6 or 5.7</td></tr><tr><td>LLM API Key</td><td>OpenAI / Anthropic / Google Gemini / DeepSeek / Zhipu GLM / MiniMax / Qwen / Kimi supported</td></tr><tr><td>Network</td><td>Internet connection required for AI model API calls</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">UE Version Compatibility</p><p>NexusFlow requires <strong>UE 5.6 or 5.7</strong>. UE 5.5 and earlier are not supported because they lack ONNX Runtime 1.20+, which is needed for the RAG embedding model.</p></div><h2 id="install-the-desktop-app-from-github" tabindex="-1">Install the Desktop App (from GitHub) <a class="header-anchor" href="#install-the-desktop-app-from-github" aria-label="Permalink to &quot;Install the Desktop App (from GitHub)&quot;">​</a></h2><p>The NexusFlow desktop app is completely free and always will be.</p><h3 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h3><p>Go to the <a href="https://github.com/maxzhao/NexusFlow/releases" target="_blank" rel="noreferrer">GitHub Releases</a> page and download the latest <code>.exe</code> installer.</p><h3 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h3><ol><li>Double-click the downloaded <code>.exe</code> installer (NSIS installer)</li><li>Select your preferred language (Simplified Chinese / English)</li><li>Choose whether to install for the current user or all users</li><li>Follow the setup wizard to choose an installation directory</li><li>Complete the installation</li></ol><p>After installation, launch NexusFlow from the Start Menu or desktop shortcut. On first launch, a floating ball icon will appear on your desktop and the first-run setup wizard will guide you through configuration.</p><h2 id="install-the-ue-plugin-from-fab" tabindex="-1">Install the UE Plugin (from Fab) <a class="header-anchor" href="#install-the-ue-plugin-from-fab" aria-label="Permalink to &quot;Install the UE Plugin (from Fab)&quot;">​</a></h2><p>NexusFlow requires a companion plugin installed in the UE Editor to communicate with the engine. The plugin is available on Fab.com.</p><h3 id="option-1-install-from-fab-recommended" tabindex="-1">Option 1: Install from Fab (Recommended) <a class="header-anchor" href="#option-1-install-from-fab-recommended" aria-label="Permalink to &quot;Option 1: Install from Fab (Recommended)&quot;">​</a></h3><ol><li>Purchase the NexusFlow plugin on <a href="https://www.fab.com/" target="_blank" rel="noreferrer">Fab.com</a></li><li>In the Epic Games Launcher, go to your Fab Library</li><li>Find NexusFlow and click <strong>Install to Engine</strong></li><li>Select UE 5.6 or 5.7 as the target engine version</li><li>Restart the UE Editor</li></ol><h3 id="option-2-manual-installation" tabindex="-1">Option 2: Manual Installation <a class="header-anchor" href="#option-2-manual-installation" aria-label="Permalink to &quot;Option 2: Manual Installation&quot;">​</a></h3><p>If you have the plugin as a zip file:</p><ol><li>Close the UE Editor</li><li>Extract the <code>NexusFlow</code> folder into your UE project&#39;s <code>Plugins/</code> directory</li><li>Reopen the UE Editor</li><li>Go to <strong>Edit &gt; Plugins</strong>, search for &quot;NexusFlow&quot;, and confirm it is enabled</li></ol><h3 id="verify-plugin-installation" tabindex="-1">Verify Plugin Installation <a class="header-anchor" href="#verify-plugin-installation" aria-label="Permalink to &quot;Verify Plugin Installation&quot;">​</a></h3><p><img src="'+e+'" alt="UE Project Settings showing NexusFlow plugin"></p><p>You can check the plugin installation status from NexusFlow&#39;s <strong>Settings &gt; About</strong> page:</p><ul><li>✅ <strong>Plugin detected</strong> — Installation successful</li><li>❌ <strong>Plugin not found</strong> — Review the installation steps or reinstall</li></ul><p>Click the &quot;Re-detect&quot; button to manually refresh the detection result.</p><h2 id="ue-plugin-first-launch" tabindex="-1">UE Plugin First Launch <a class="header-anchor" href="#ue-plugin-first-launch" aria-label="Permalink to &quot;UE Plugin First Launch&quot;">​</a></h2><p>When the UE Editor starts with the NexusFlow plugin installed, the plugin automatically checks your environment. If anything is missing, a <strong>NexusFlow Setup</strong> dialog appears.</p><h3 id="what-gets-checked" tabindex="-1">What Gets Checked <a class="header-anchor" href="#what-gets-checked" aria-label="Permalink to &quot;What Gets Checked&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>What It Checks</th><th>How</th></tr></thead><tbody><tr><td><strong>NexusFlow Desktop App</strong></td><td>Whether the app is installed on this machine</td><td>Windows Registry lookup</td></tr><tr><td><strong>Embedding Model</strong></td><td>Whether the RAG search model is ready</td><td>Bridge FFI status check</td></tr></tbody></table><h3 id="when-the-dialog-appears" tabindex="-1">When the Dialog Appears <a class="header-anchor" href="#when-the-dialog-appears" aria-label="Permalink to &quot;When the Dialog Appears&quot;">​</a></h3><ul><li><strong>Everything ready</strong> — No dialog; the plugin starts silently</li><li><strong>Something missing</strong> — The setup dialog appears after a short delay (~2 seconds)</li><li><strong>&quot;Don&#39;t Show Again&quot; was selected</strong> — No dialog, even if items are missing</li></ul><h3 id="dialog-options" tabindex="-1">Dialog Options <a class="header-anchor" href="#dialog-options" aria-label="Permalink to &quot;Dialog Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Download Model</strong></td><td>Starts downloading the embedding model (~90 MB) in the background</td></tr><tr><td><strong>Open Settings</strong></td><td>Opens <strong>Project Settings &gt; Plugins &gt; NexusFlow</strong> for manual configuration</td></tr><tr><td><strong>Later</strong></td><td>Dismisses the dialog; it will appear again on next startup</td></tr><tr><td><strong>Don&#39;t Show Again</strong></td><td>Permanently hides the dialog (can be re-enabled in settings)</td></tr></tbody></table><h3 id="not-installed-app-links" tabindex="-1">Not-Installed App Links <a class="header-anchor" href="#not-installed-app-links" aria-label="Permalink to &quot;Not-Installed App Links&quot;">​</a></h3><p>If the NexusFlow desktop app is not detected, the dialog provides two download links:</p><ul><li><strong>GitHub</strong> — <a href="https://github.com/maxzhao/NexusFlow/releases/latest" target="_blank" rel="noreferrer">Releases page</a></li><li><strong>Mirror</strong> — Accelerated download link for users in China</li></ul><h3 id="re-enabling-the-setup-dialog" tabindex="-1">Re-enabling the Setup Dialog <a class="header-anchor" href="#re-enabling-the-setup-dialog" aria-label="Permalink to &quot;Re-enabling the Setup Dialog&quot;">​</a></h3><p>If you previously clicked &quot;Don&#39;t Show Again&quot; and want to see the dialog again:</p><ol><li>Navigate to the NexusFlow config file: <code>%LOCALAPPDATA%/NexusFlow/config.json</code></li><li>Set <code>&quot;showSetupWizard&quot;: true</code></li><li>Restart the UE Editor</li></ol><p>Alternatively, you can check environment status at any time in <strong>Project Settings &gt; Plugins &gt; NexusFlow</strong>.</p><h2 id="configure-ai-models" tabindex="-1">Configure AI Models <a class="header-anchor" href="#configure-ai-models" aria-label="Permalink to &quot;Configure AI Models&quot;">​</a></h2><p>NexusFlow requires at least one AI model to be configured before use. There are two ways to set this up:</p><h3 id="option-1-first-run-wizard" tabindex="-1">Option 1: First-Run Wizard <a class="header-anchor" href="#option-1-first-run-wizard" aria-label="Permalink to &quot;Option 1: First-Run Wizard&quot;">​</a></h3><p>On first launch, Step 2 of the wizard will guide you through AI model configuration. See <a href="./getting-started#step-2-configure-ai-model">Quick Start</a> for details.</p><h3 id="option-2-settings-page" tabindex="-1">Option 2: Settings Page <a class="header-anchor" href="#option-2-settings-page" aria-label="Permalink to &quot;Option 2: Settings Page&quot;">​</a></h3><ol><li>Click the gear icon at the top of the sidebar to open Settings</li><li>Select <strong>AI Models</strong></li><li>Click &quot;Add Model&quot;</li><li>Fill in the configuration fields (see below)</li></ol><p><img src="'+o+'" alt="Add Model configuration form"></p><h3 id="supported-ai-model-providers" tabindex="-1">Supported AI Model Providers <a class="header-anchor" href="#supported-ai-model-providers" aria-label="Permalink to &quot;Supported AI Model Providers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Provider</th><th>Example Models</th><th>Notes</th></tr></thead><tbody><tr><td><strong>OpenAI</strong></td><td><code>gpt-5.4</code>, <code>gpt-5.3-codex</code></td><td>OpenAI official API</td></tr><tr><td><strong>Anthropic</strong></td><td><code>claude-opus-4-6</code>, <code>claude-sonnet-4-20250514</code></td><td>Max Tokens is required</td></tr><tr><td><strong>Google Gemini</strong></td><td><code>gemini-3.1-pro-preview</code>, <code>gemini-2.5-pro</code></td><td>Google AI Studio API</td></tr><tr><td><strong>DeepSeek</strong></td><td><code>deepseek-chat</code>, <code>deepseek-reasoner</code></td><td>Cost-effective option</td></tr><tr><td><strong>Zhipu GLM</strong></td><td><code>GLM-4.7</code>, <code>GLM-5</code></td><td>Model names are case-sensitive</td></tr><tr><td><strong>MiniMax</strong></td><td><code>MiniMax-M2.7</code>, <code>MiniMax-M2.7-highspeed</code></td><td>Max Tokens is required</td></tr><tr><td><strong>Qwen</strong></td><td><code>qwen3-max</code>, <code>qwen3.5-plus</code></td><td>Alibaba Cloud DashScope API</td></tr><tr><td><strong>Kimi</strong></td><td><code>kimi-k2.5</code>, <code>kimi-k2-turbo-preview</code></td><td>Moonshot API</td></tr><tr><td><strong>Custom</strong></td><td>User-defined models</td><td>Supports any API compatible with the above protocols</td></tr></tbody></table><h3 id="configuration-fields" tabindex="-1">Configuration Fields <a class="header-anchor" href="#configuration-fields" aria-label="Permalink to &quot;Configuration Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>Provider</td><td>✅</td><td>Select the model provider</td></tr><tr><td>Model Name</td><td>✅</td><td>Custom display name shown in the model list</td></tr><tr><td>API Key</td><td>✅</td><td>API key provided by the provider, or an environment variable reference such as <code>${OPENAI_API_KEY}</code></td></tr><tr><td>Model ID</td><td>✅</td><td>Model identifier, e.g., <code>gpt-5.4</code></td></tr><tr><td>API URL</td><td>Required for Custom</td><td>Custom API endpoint URL</td></tr><tr><td>Protocol</td><td>Required for Custom</td><td>OpenAI Compatible / OpenAI Responses API / Anthropic Messages API / Google Gemini API</td></tr><tr><td>Temperature</td><td>Optional</td><td>Generation randomness (0–2); higher values produce more varied outputs</td></tr><tr><td>Max Tokens</td><td>Optional*</td><td>Maximum output tokens. *Required when using the Anthropic protocol</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can add multiple models and set one as the default. Click a model card in the list to view its details and manage it.</p></div><div class="warning custom-block"><p class="custom-block-title">API Key Security</p><p>API keys can be entered directly, or referenced with <code>${ENV_NAME}</code> such as <code>${OPENAI_API_KEY}</code>. Directly entered API keys are displayed in masked form (<code>sk-****</code>) in the UI, with an eye icon to toggle visibility; environment variable references are shown as variable names. Real API keys stay local, and environment variable mode avoids storing the real key in app configuration.</p></div><h2 id="verify-your-setup" tabindex="-1">Verify Your Setup <a class="header-anchor" href="#verify-your-setup" aria-label="Permalink to &quot;Verify Your Setup&quot;">​</a></h2><p>After installing both components, run through this checklist to confirm everything is working:</p><ol><li><strong>Launch NexusFlow</strong> — The floating ball appears on screen</li><li><strong>Click the floating ball</strong> — The sidebar opens normally</li><li><strong>Check models</strong> — Settings &gt; AI Models shows at least one model with a passing validation status</li><li><strong>Launch UE</strong> — The sidebar status bar shows a green connection indicator</li><li><strong>Send a message</strong> — Try typing &quot;Hello&quot; to confirm the AI responds</li></ol><p>If you encounter any issues, see <a href="./../faq/troubleshooting">Troubleshooting</a>.</p>',57)])])}const w=a(l,[["render",s]]);export{b as __pageData,w as default};
